using System.Collections.ObjectModel;using System.Security.Cryptography;using System.Text;using ClosedXML.Excel;using GmpCompanyCollector.App.Models;using GmpCompanyCollector.App.Utilities;
namespace GmpCompanyCollector.App.Services;
public interface IDataGoApiClient{Task<ApiResponse<CompanyListItem>> GetCompanyListPageAsync(CollectionOptions o,int page,CancellationToken ct);Task<ApiResponse<FactoryDetailItem>> GetFactoryDetailPageAsync(CollectionOptions o,int page,CancellationToken ct);Task<List<T>> CollectPagesAsync<T>(Func<int,CancellationToken,Task<ApiResponse<T>>> fetch,int rows,IProgress<CollectionProgress>? progress,CancellationToken ct);}
public class DataGoApiClient(HttpClient? http=null):IDataGoApiClient{readonly HttpClient _http=http??new(){Timeout=TimeSpan.FromSeconds(30)}; public async Task<ApiResponse<CompanyListItem>> GetCompanyListPageAsync(CollectionOptions o,int page,CancellationToken ct)=>ApiResponseParser.ParseCompanyList(await GetAsync(ApiUrlBuilder.Build("getDrugBsshListInq",o,page),ct)); public async Task<ApiResponse<FactoryDetailItem>> GetFactoryDetailPageAsync(CollectionOptions o,int page,CancellationToken ct)=>ApiResponseParser.ParseFactoryDetails(await GetAsync(ApiUrlBuilder.Build("getDrugBsshItemInq",o,page),ct)); async Task<string> GetAsync(Uri uri,CancellationToken ct){for(int a=0;;a++){try{var r=await _http.GetAsync(uri,ct); var s=await r.Content.ReadAsStringAsync(ct); if((int)r.StatusCode is 408 or 429 or 500 or 502 or 503 or 504)throw new HttpRequestException("retry",null,r.StatusCode); return s;}catch(Exception) when(a<3&&!ct.IsCancellationRequested){await Task.Delay(TimeSpan.FromSeconds(Math.Pow(2,a)),ct);}}}
 public async Task<List<T>> CollectPagesAsync<T>(Func<int,CancellationToken,Task<ApiResponse<T>>> fetch,int rows,IProgress<CollectionProgress>? progress,CancellationToken ct){var result=new List<T>(); string? last=null; var start=DateTimeOffset.Now; var first=await fetch(1,ct); if(!first.IsSuccess)throw new InvalidOperationException(first.Header.ResultMsg); result.AddRange(first.Body.Items); var pages=ApiUrlBuilder.CalculateTotalPages(first.Body.TotalCount,rows); if(pages==0)pages=first.Body.Items.Count>0?1:0; progress?.Report(new(){CurrentPage=1,TotalPages=pages,ReceivedCount=result.Count,TotalExpectedCount=first.Body.TotalCount,SuccessRequests=1,Elapsed=DateTimeOffset.Now-start}); last=string.Join('|',first.Body.Items.Select(x=>x?.GetHashCode())); for(int p=2;p<=Math.Min(pages,10000);p++){ct.ThrowIfCancellationRequested(); var r=await fetch(p,ct); var hash=string.Join('|',r.Body.Items.Select(x=>x?.GetHashCode())); if(r.Body.Items.Count==0||hash==last)break; last=hash; result.AddRange(r.Body.Items); progress?.Report(new(){CurrentPage=p,TotalPages=pages,ReceivedCount=result.Count,TotalExpectedCount=r.Body.TotalCount,SuccessRequests=p,Elapsed=DateTimeOffset.Now-start}); await Task.Delay(150,ct);} return result;}}
public class ApiKeyStorageService{readonly string _path=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),"GmpCompanyCollector","settings.dat"); public void Save(string key){Directory.CreateDirectory(Path.GetDirectoryName(_path)!); var b=ProtectedData.Protect(Encoding.UTF8.GetBytes(key),null,DataProtectionScope.CurrentUser); File.WriteAllBytes(_path,b);} public string? Load(){try{return File.Exists(_path)?Encoding.UTF8.GetString(ProtectedData.Unprotect(File.ReadAllBytes(_path),null,DataProtectionScope.CurrentUser)):null;}catch{return null;}} public void Delete(){if(File.Exists(_path))File.Delete(_path);}}
public class LogService{public ObservableCollection<string> Entries{get;}=[]; readonly string dir=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),"GmpCompanyCollector","logs"); public void Info(string m)=>Write("정보",m); public void Warn(string m)=>Write("경고",m); public void Error(string m)=>Write("오류",m); void Write(string l,string m){Directory.CreateDirectory(dir); m=SensitiveDataMasker.MaskUrl(m); var line=$"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {l}: {m}"; Entries.Add(line); File.AppendAllText(Path.Combine(dir,$"GmpCompanyCollector_{DateTime.Now:yyyyMMdd}.log"),line+Environment.NewLine,Encoding.UTF8);}}
public class StatisticsService{public BasicStatistics Basic(IEnumerable<CompanyListItem> c,IEnumerable<FactoryDetailItem> f){var cl=c.ToList();var fl=f.ToList();return new(cl.Count,cl.Select(x=>x.NormalizedEntrps).Where(x=>x!="").Distinct().Count(),cl.Select(x=>x.PrmisnNo).Where(x=>x!="").Distinct().Count(),fl.Count,fl.Count(x=>x.CombinedFactoryAddress!=""),fl.Count(x=>x.Telno!=""),cl.Count(x=>x.Entrps=="")+fl.Count(x=>x.Entrps==""),cl.Count(x=>x.PrmisnNo=="")+fl.Count(x=>x.PrmisnNo==""),cl.Count(x=>x.Adres=="")+fl.Count(x=>x.CombinedFactoryAddress==""),cl.Count(x=>x.Rprsntv=="")+fl.Count(x=>x.Rprsntv==""),cl.Count(x=>!x.IsValidDate&&x.PrmisnDt!="")+fl.Count(x=>!x.IsValidDate&&x.PrmisnDt!=""),cl.Count(x=>x.IsDuplicate)+fl.Count(x=>x.IsDuplicate));} public void MarkDuplicates(IList<CompanyListItem> c,IList<FactoryDetailItem> f){Mark(c,x=>$"{x.PrmisnNo}|{x.Induty}|{x.Entrps}|{x.Adres}");Mark(f,x=>$"{x.PrmisnNo}|{x.Sn}|{x.FctryNm}|{x.FctryAddr1}|{x.FctryAddr2}");} static void Mark<T>(IList<T> items,Func<T,string> key){int g=1; foreach(var group in items.GroupBy(key).Where(x=>x.Count()>1)){foreach(dynamic i in group){i.IsDuplicate=true;i.DuplicateGroupNo=g;}g++;}}}
public class CsvExportService{public void ExportCompanies(string path,IEnumerable<CompanyListItem> rows){File.WriteAllText(path,"\uFEFF번호,업종,업체명,업체허가번호,공장주소\n"+string.Join('\n',rows.Select((r,i)=>$"{i+1},{Esc(r.Induty)},{Esc(r.Entrps)},{Esc(r.PrmisnNo)},{Esc(r.Adres)}")),Encoding.UTF8);} static string Esc(string s)=>s.Contains(',')||s.Contains('"')||s.Contains('\n')?$"\"{s.Replace("\"","\"\"")}\"":s;}
public class ExcelExportService{public void Export(string path,IEnumerable<CompanyListItem> companies,IEnumerable<FactoryDetailItem> factories,BasicStatistics? stats=null){using var wb=new XLWorkbook(); var info=wb.AddWorksheet("수집정보"); info.Cell(1,1).Value="수집일시"; info.Cell(1,2).Value=DateTime.Now; info.Cell(2,1).Value="API 서비스명"; info.Cell(2,2).Value="의약품 등 업체허가현황"; var ws=wb.AddWorksheet("업체목록"); string[] h=["번호","업종","업체명","정규화업체명","대표자명","업체허가일자","업체허가일자원본","업체허가번호","공장주소","시도","시군구","중복여부","중복그룹번호"]; for(int i=0;i<h.Length;i++)ws.Cell(1,i+1).Value=h[i]; int r=2; foreach(var x in companies){ws.Cell(r,1).Value=r-1;ws.Cell(r,2).Value=x.Induty;ws.Cell(r,3).Value=x.Entrps;ws.Cell(r,4).Value=x.NormalizedEntrps;ws.Cell(r,8).Value="'"+x.PrmisnNo;ws.Cell(r,9).Value=x.Adres;r++;} var fs=wb.AddWorksheet("제조소상세"); string[] fh=["번호","업체명","정규화업체명","업종","업체허가번호","대표자명","업체허가일자","업체허가일자원본","공장일련번호","공장명","공장전화번호","공장주소1","공장주소2","통합공장주소","시도","시군구","중복여부","중복그룹번호"]; for(int i=0;i<fh.Length;i++)fs.Cell(1,i+1).Value=fh[i]; r=2; foreach(var x in factories){fs.Cell(r,1).Value=r-1;fs.Cell(r,2).Value=x.Entrps;fs.Cell(r,5).Value="'"+x.PrmisnNo;fs.Cell(r,11).Value="'"+x.Telno;r++;} wb.AddWorksheet("업종별통계");wb.AddWorksheet("지역별통계");wb.AddWorksheet("오류및누락"); foreach(var s in wb.Worksheets){s.Row(1).Style.Font.Bold=true;s.SheetView.FreezeRows(1); if(s.LastRowUsed()!=null)s.RangeUsed()!.SetAutoFilter(); s.Columns().AdjustToContents();} wb.SaveAs(path);}}
